={{ JSON.stringify({ model: 'llama3:8b', prompt: `You are a data extraction specialist. Extract structured data from unstructured text.

Context: ${$json.context}

Target schema (extract these fields):
${$json.schema}

Text to extract from:
${$json.text}

Rules:
1. Return ONLY a valid JSON array of objects matching the schema
2. If a field cannot be found, use null
3. Extract ALL matching entities (there may be multiple)
4. Be precise — only extract what is clearly stated
5. Do not invent or hallucinate data

Return ONLY the JSON array, no explanation.`, stream: false, options: { temperature: 0.1, num_predict: 4000 } }) }}

parameters.jsCode:
const response = $input.first().json.response;

let extracted;
try {
  // Find JSON array in response
  const arrayMatch = response.match(/\[[\s\S]*\]/);
  if (arrayMatch) {
    extracted = JSON.parse(arrayMatch[0]);
  } else {
    // Try single object
    const objMatch = response.match(/\{[\s\S]*\}/);
    extracted = objMatch ? [JSON.parse(objMatch[0])] : [];
  }
} catch (e) {
  extracted = [{ raw_response: response, parse_error: e.message }];
}

return [{ json: { extracted_count: extracted.length, data: extracted } }];
